ValidationRule.errorConditionFormula:
AND(
    NOT($Setup.RES_Config_Switch__c.RES_Validation_Rules_Off__c),

    /* Apply only for specific Record Types */
    OR(
        $RecordType.DeveloperName = "RES_Residential_Single_Buyer",
        $RecordType.DeveloperName = "RES_Residential_Multi_Buyer"
    ),

    /* Stage = Closed Lost */
    ISPICKVAL(StageName, "Closed Lost"),

    /* Reason for Lost is blank */
    ISPICKVAL(RES_Reason_for_Lost__c, "")
)
